INSERT INTO partners (name_en, name_zh, name_fr, name_ja, description_en, description_zh, description_fr, description_ja, type, website, is_visible, display_order, created_at, updated_at) VALUES 
('Asia Art Healing Research Institute', '亚洲艺术疗愈研究院', 'Institut de Recherche en Art-Thérapie d''Asie', 'アジア芸術ヒーリング研究所', 'A leading Asia-Pacific nonprofit dedicated to advancing art therapy research, professional certification, and community healing programs. APHA brings together top experts, research institutions, and practitioners across 15+ countries to promote holistic well-being through music, painting, dance, calligraphy, and drama therapy.', '亚太地区领先的艺术疗愈非营利组织，致力于推进艺术疗愈研究、专业认证与社区疗愈项目。APHA 汇聚 15+ 国家的顶尖专家、研究机构与实践者，通过音乐、绘画、舞蹈、书法、戏剧等多元艺术形式促进身心健康与社会福祉。', 'Organisation à but non lucratif de premier plan en Asie-Pacifique, dédiée à la recherche en art-thérapie, à la certification professionnelle et aux programmes de guérison communautaire à travers la musique, la peinture, la danse et le théâtre.', 'アジア太平洋地域をリードする芸術療法の非営利組織。音楽、絵画、ダンス、書道、演劇を通じた心身の健康と社会福祉の促進に取り組んでいます。', 'affiliate', '/apha', 1, 1, NOW(), NOW()),
('Swiss ManaEndless Association', '瑞士无魔协会', 'Association Suisse ManaEndless', 'スイス・マナエンドレス協会', 'An international nonprofit cultural organization headquartered in Geneva, Switzerland, dedicated to promoting global civilizational dialogue and humanistic heritage through contemporary art exhibitions and cross-cultural exchange. ManaEndless curates exhibitions across Swiss cultural capitals and partners with UNESCO, Art Basel, and leading global institutions.', '总部位于瑞士日内瓦的国际非营利文化组织，致力于通过当代艺术展览与跨文化交流，促进全球文明对话与人文价值传承。无魔协会在瑞士文化重镇策划国际艺术展览，与联合国教科文组织、巴塞尔艺术展等全球顶级机构深度合作。', 'Organisation culturelle internationale à but non lucratif basée à Genève, Suisse, dédiée à la promotion du dialogue civilisationnel mondial et du patrimoine humaniste à travers des expositions d''art contemporain et des échanges interculturels.', 'スイス・ジュネーブに本部を置く国際非営利文化組織。現代美術展と異文化交流を通じて、グローバルな文明対話と人文的価値の継承を推進しています。', 'affiliate', '/manaendless', 1, 2, NOW(), NOW());

